import numpy as np

# {In this novel algorithm, select the next node based on the shortest travel distance to an unvisited node and the increase in network connectivity that visiting this node would provide, prioritizing nodes that reduce the travel distance for other trucks.}

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node if current_node != depot_node else None

    factors = []

    for node in unvisited_nodes:
        distance_to_current = distance_matrix[current_node, node]
        connectivity_increase = np.sum([distance_matrix[truck, node] - distance_to_current 
                                        for truck in truck_nodes if truck != node])

        combined_factor = (1 / (distance_to_current + 1e-5)) + connectivity_increase
        factors.append((combined_factor, node))

    factors.sort(reverse=True)
    _, next_node = factors[0]

    return next_node
